const demoProfiles = [
  {
    profileName: 'support-classifier',
    systemPrompt: 'Classify the sentiment of the customer message as exactly one lowercase word: positive, negative, or neutral. Reply with only that single word and nothing else.',
    model: 'openai/gpt-oss-20b:free',
    temperature: 0,
  },
  {
    profileName: 'support-writer',
    systemPrompt: 'You are a customer support agent. Reply to the customer in one short, polite sentence.',
    model: 'google/gemma-4-31b-it:free',
    temperature: 0,
  },
];

return demoProfiles.map((profile) => ({ json: profile }));

const demoCases = [
  { profile: 'support-classifier', label: 'angry late order', input: 'This is the third time my order is late. I want a refund now.', expected: 'negative', checkType: 'exact' },
  { profile: 'support-classifier', label: 'happy fast delivery', input: 'Thank you so much, the delivery was incredibly fast!', expected: 'positive', checkType: 'exact' },
  { profile: 'support-classifier', label: 'neutral hours question', input: 'What are your opening hours on Sunday?', expected: 'neutral', checkType: 'exact' },
  { profile: 'support-writer', label: 'broken item apology', input: 'My package arrived broken.', expected: 'Reply apologizes for the problem and offers a concrete next step such as a replacement or refund.', checkType: 'llm-judge' },
  { profile: 'support-writer', label: 'sunday opening', input: 'Are you open on Sunday?', expected: 'Sunday', checkType: 'contains' },
];

return demoCases.map((testCase) => ({ json: testCase }));

const validCheckTypes = ['exact', 'contains', 'regex', 'numeric', 'llm-judge'];

const rowsOf = (nodeName) => {
  try {
    return $(nodeName).all().map((item) => item.json).filter((row) => row && row.id != null);
  } catch {
    return [];
  }
};

const loadProfiles = () => {
  const loadedRows = rowsOf('Load profiles');
  return loadedRows.length > 0 ? loadedRows : rowsOf('Seed profiles');
};

const isBlank = (value) => !value || String(value).trim() === '';

const findInvalidReason = (testCase, checkType, profile) => {
  if (isBlank(testCase.input)) return 'empty input';
  if (isBlank(testCase.expected)) return 'empty expected';
  if (!validCheckTypes.includes(checkType)) return 'unknown checkType: ' + checkType;
  if (!profile) return 'profile not found: ' + (testCase.profile || '(none)');
  return null;
};

const testCase = $input.item.json;
const checkType = (testCase.checkType && String(testCase.checkType).trim()) || 'exact';
const profile = loadProfiles().find((candidate) => candidate.profileName === testCase.profile);
const invalidReason = findInvalidReason(testCase, checkType, profile);

$input.item.json = {
  caseId: testCase.id ?? null,
  label: testCase.label ?? '(unlabeled)',
  profile: testCase.profile ?? null,
  input: testCase.input ?? '',
  expected: testCase.expected ?? '',
  checkType,
  valid: invalidReason == null,
  reason: invalidReason ?? '',
  systemPrompt: profile ? profile.systemPrompt : '',
  model: profile ? profile.model : '',
  temperature: profile ? (profile.temperature ?? 0) : 0,
};
return $input.item;

const scoreRange = Object.freeze({ min: 1, max: 5 });
const maxReasonLength = 200;
const defaultJudgeScoreThreshold = 4;

const buildResultBase = (source) => ({
  caseId: source.caseId,
  label: source.label,
  profile: source.profile,
  checkType: 'llm-judge',
  scored: true,
});

const extractResponseText = (response) => {
  if (response.choices && response.choices[0] && response.choices[0].message) {
    return response.choices[0].message.content;
  }
  return response.text ?? response.response ?? response.output ?? (typeof response === 'string' ? response : JSON.stringify(response));
};

const parseJudgement = (text) => {
  try {
    const jsonCandidate = String(text).match(/\{[\s\S]*\}/);
    return JSON.parse(jsonCandidate ? jsonCandidate[0] : String(text));
  } catch {
    return null;
  }
};

const clampScore = (score) => Math.max(scoreRange.min, Math.min(scoreRange.max, score));

const finishWith = (result) => {
  $input.item.json = result;
  return $input.item;
};

const config = $('Config').first().json;
const passThreshold = Number(config.judgeScoreThreshold ?? defaultJudgeScoreThreshold);
const source = $('Attach case fields').item.json;
const base = buildResultBase(source);

if (source.error || source.actualOutput == null) {
  return finishWith({ ...base, pass: null, error: true, detail: 'model call failed' });
}

const judgement = parseJudgement(extractResponseText($input.item.json));
if (!judgement || typeof judgement.score !== 'number') {
  return finishWith({ ...base, pass: null, judgeError: true, detail: 'judge returned non-JSON' });
}

const score = clampScore(judgement.score);
return finishWith({
  ...base,
  score,
  pass: score >= passThreshold,
  reason: String(judgement.reason ?? '').slice(0, maxReasonLength),
});

const maxDetailLength = 70;

const normalize = (value) => String(value ?? '').trim();

const firstNumber = (value) => {
  const match = String(value).match(/-?\d+(?:\.\d+)?/);
  return match ? Number(match[0]) : NaN;
};

const checkers = new Map([
  ['exact', (actual, expected) => ({ pass: actual.toLowerCase() === expected.toLowerCase(), detail: '' })],
  ['contains', (actual, expected) => ({ pass: actual.toLowerCase().includes(expected.toLowerCase()), detail: '' })],
  ['numeric', (actual, expected) => {
    const actualNumber = firstNumber(actual);
    const expectedNumber = firstNumber(expected);
    return {
      pass: Number.isFinite(actualNumber) && Number.isFinite(expectedNumber) && actualNumber === expectedNumber,
      detail: '',
    };
  }],
  ['regex', (actual, expected) => {
    try {
      return { pass: new RegExp(expected).test(actual), detail: '' };
    } catch {
      return { pass: false, detail: 'invalid regex' };
    }
  }],
]);

const runCheck = (checkType, actual, expected) => {
  const checker = checkers.get(checkType);
  return checker ? checker(actual, expected) : { pass: false, detail: '' };
};

const describeFailure = (expected, actual) =>
  'expected ' + expected.slice(0, maxDetailLength) + ' | got ' + actual.slice(0, maxDetailLength);

const toCheckResult = (caseResult) => {
  const base = {
    caseId: caseResult.caseId,
    label: caseResult.label,
    profile: caseResult.profile,
    checkType: caseResult.checkType,
    scored: true,
  };
  if (caseResult.error || caseResult.actualOutput == null) {
    return { ...base, pass: null, error: true, detail: 'model call failed' };
  }
  const actual = normalize(caseResult.actualOutput);
  const expected = normalize(caseResult.expected);
  const { pass, detail } = runCheck(caseResult.checkType || 'exact', actual, expected);
  return { ...base, pass, detail: detail || (pass ? '' : describeFailure(expected, actual)) };
};

return $input.all().map((item) => ({ json: toCheckResult(item.json) }));

const defaultConfig = Object.freeze({
  judgeScoreThreshold: 4,
  regressionPassRatePp: 5,
  regressionJudgeScoreDrop: 0.5,
  maxCases: 50,
});

class ProfileStats {
  constructor(profileName) {
    this.profileName = profileName;
    this.evaluated = 0;
    this.passCount = 0;
    this.judgeScoreSum = 0;
    this.judgeScoreCount = 0;
  }

  addResult(pass) {
    this.evaluated += 1;
    if (pass) this.passCount += 1;
  }

  addJudgeScore(score) {
    this.judgeScoreSum += score;
    this.judgeScoreCount += 1;
  }

  toSummary() {
    return {
      profile: this.profileName,
      evaluated: this.evaluated,
      passCount: this.passCount,
      passRate: this.evaluated > 0 ? this.passCount / this.evaluated : null,
      judgeAvgScore: this.judgeScoreCount > 0 ? this.judgeScoreSum / this.judgeScoreCount : null,
    };
  }
}

class RunAggregator {
  constructor() {
    this.total = 0;
    this.passCount = 0;
    this.failCount = 0;
    this.errorCount = 0;
    this.invalidCount = 0;
    this.judgeScoreSum = 0;
    this.judgeScoreCount = 0;
    this.profiles = new Map();
    this.perCase = [];
    this.failing = [];
  }

  add(result) {
    this.total += 1;
    const label = result.label || '(unlabeled)';
    if (result.valid === false) {
      this.addInvalid(label, result.reason);
    } else if (this.isErrored(result)) {
      this.addError(label, result.judgeError === true);
    } else {
      this.addScored(result, label);
    }
  }

  isErrored(result) {
    return result.error === true || result.judgeError === true || result.pass === null || result.pass === undefined;
  }

  addInvalid(label, reason) {
    this.invalidCount += 1;
    this.failing.push({ label, detail: 'invalid: ' + (reason || '') });
  }

  addError(label, isJudgeError) {
    this.errorCount += 1;
    this.failing.push({ label, detail: isJudgeError ? 'judge error' : 'model error' });
  }

  addScored(result, label) {
    const stats = this.profileStats(result.profile || '(none)');
    stats.addResult(result.pass);
    this.perCase.push({ caseId: result.caseId, pass: result.pass, label });
    if (result.pass) {
      this.passCount += 1;
    } else {
      this.failCount += 1;
      this.failing.push({ label, detail: result.detail || String(result.reason || '') });
    }
    if (typeof result.score === 'number') {
      stats.addJudgeScore(result.score);
      this.judgeScoreSum += result.score;
      this.judgeScoreCount += 1;
    }
  }

  profileStats(profileName) {
    if (!this.profiles.has(profileName)) {
      this.profiles.set(profileName, new ProfileStats(profileName));
    }
    return this.profiles.get(profileName);
  }

  buildSummary(config, runAt) {
    const evaluated = this.passCount + this.failCount;
    const maxCases = Number(config.maxCases ?? defaultConfig.maxCases);
    return {
      runAt,
      total: this.total,
      evaluated,
      passCount: this.passCount,
      failCount: this.failCount,
      errorCount: this.errorCount,
      invalidCount: this.invalidCount,
      passRate: evaluated > 0 ? this.passCount / evaluated : null,
      judgeAvgScore: this.judgeScoreCount > 0 ? this.judgeScoreSum / this.judgeScoreCount : null,
      perProfile: [...this.profiles.values()].map((stats) => stats.toSummary()),
      truncated: this.total >= maxCases,
      emptyDataset: this.total === 0,
      configEcho: {
        judgeScoreThreshold: Number(config.judgeScoreThreshold ?? defaultConfig.judgeScoreThreshold),
        regressionPassRatePp: Number(config.regressionPassRatePp ?? defaultConfig.regressionPassRatePp),
        regressionJudgeScoreDrop: Number(config.regressionJudgeScoreDrop ?? defaultConfig.regressionJudgeScoreDrop),
      },
    };
  }
}

const config = $('Config').first().json;
const aggregator = new RunAggregator();
for (const item of $input.all()) {
  aggregator.add(item.json);
}

return [{
  json: {
    summary: aggregator.buildSummary(config, new Date().toISOString()),
    perCase: aggregator.perCase,
    failing: aggregator.failing,
  },
}];

const VERDICT = Object.freeze({
  baseline: 'baseline',
  rebaseline: 'rebaseline',
  regression: 'regression',
  recovered: 'recovered',
  ops: 'ops',
  ok: 'ok',
});

const defaultThresholds = Object.freeze({
  regressionPassRatePp: 5,
  regressionJudgeScoreDrop: 0.5,
});

const parseJson = (value, fallback) => {
  if (typeof value !== 'string') return value ?? fallback;
  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
};

const parseSnapshot = (rows) => {
  if (!rows || rows.length === 0) return null;
  const row = rows[0].json ?? rows[0];
  if (row == null || row.id == null) return null;
  const summary = parseJson(row.summary, null);
  if (!summary) return null;
  return { runAt: row.runAt, summary, results: parseJson(row.results, []) };
};

const fetchRows = (nodeName) => {
  try {
    return $(nodeName).all();
  } catch {
    return [];
  }
};

const passMapOf = (results) => {
  const map = {};
  for (const caseResult of (results || [])) map[caseResult.caseId] = caseResult.pass;
  return map;
};

const classifyFlips = (currentCases, baselinePass, previousPass, hasPrevious) => {
  const regressed = [];
  const newFailing = [];
  const recovered = [];
  for (const currentCase of currentCases) {
    const passedInBaseline = baselinePass[currentCase.caseId];
    if (passedInBaseline === true && currentCase.pass === false) {
      regressed.push({
        caseId: currentCase.caseId,
        label: currentCase.label,
        confirmed: hasPrevious ? previousPass[currentCase.caseId] === false : false,
      });
    } else if (passedInBaseline === undefined && currentCase.pass === false) {
      newFailing.push({ caseId: currentCase.caseId, label: currentCase.label });
    } else if (passedInBaseline === false && currentCase.pass === true) {
      recovered.push({ caseId: currentCase.caseId, label: currentCase.label });
    }
  }
  return { regressed, newFailing, recovered };
};

const deltaOrNull = (currentValue, baselineValue, scale = 1) =>
  (currentValue != null && baselineValue != null) ? (currentValue - baselineValue) * scale : null;

const judgeThresholdChanged = (baselineSummary, currentSummary) =>
  !!(baselineSummary.configEcho && currentSummary.configEcho
    && baselineSummary.configEcho.judgeScoreThreshold !== currentSummary.configEcho.judgeScoreThreshold);

const detectOpsFailure = (summary) => {
  const brokenCount = (summary.errorCount || 0) + (summary.invalidCount || 0);
  const brokenRatio = summary.total ? brokenCount / summary.total : 0;
  return summary.emptyDataset === true || (summary.evaluated || 0) === 0 || brokenRatio > 0.5;
};

const captureBaseline = (hasBaseline, opsFailed) => {
  if (opsFailed) return { verdict: VERDICT.ops, markAsBaseline: false, shouldAlert: true, compare: {} };
  return {
    verdict: hasBaseline ? VERDICT.rebaseline : VERDICT.baseline,
    markAsBaseline: true,
    shouldAlert: true,
    compare: {},
  };
};

const compareAgainstBaseline = ({ baseline, previous, currentSummary, currentCases, opsFailed }) => {
  const thresholds = currentSummary.configEcho || defaultThresholds;
  const baselineSummary = baseline.summary;
  const passRateDeltaPp = deltaOrNull(currentSummary.passRate, baselineSummary.passRate, 100);
  const judgeScoreDelta = deltaOrNull(currentSummary.judgeAvgScore, baselineSummary.judgeAvgScore);
  const flips = classifyFlips(
    currentCases,
    passMapOf(baseline.results),
    previous ? passMapOf(previous.results) : {},
    previous != null,
  );
  const thresholdChanged = judgeThresholdChanged(baselineSummary, currentSummary);
  const confirmed = flips.regressed.filter((flip) => flip.confirmed);
  const passRateDropped = passRateDeltaPp != null
    && passRateDeltaPp <= -Number(thresholds.regressionPassRatePp ?? defaultThresholds.regressionPassRatePp);
  const judgeScoreDropped = judgeScoreDelta != null
    && judgeScoreDelta <= -Number(thresholds.regressionJudgeScoreDrop ?? defaultThresholds.regressionJudgeScoreDrop);
  const isRegression = passRateDropped || confirmed.length > 0 || (judgeScoreDropped && !thresholdChanged);

  const compare = {
    passRateDeltaPp,
    judgeScoreDelta,
    thresholdChanged,
    regressed: flips.regressed,
    confirmed,
    newFailing: flips.newFailing,
    recovered: flips.recovered,
    baselineRunAt: baseline.runAt,
    prevRunAt: previous ? previous.runAt : null,
    prevPassRate: previous ? previous.summary.passRate : null,
  };

  if (isRegression) return { verdict: VERDICT.regression, markAsBaseline: false, shouldAlert: true, compare };
  if (opsFailed) return { verdict: VERDICT.ops, markAsBaseline: false, shouldAlert: true, compare };

  const previousVerdict = previous ? previous.summary.verdict : null;
  if (previousVerdict === VERDICT.regression || previousVerdict === VERDICT.ops) {
    return { verdict: VERDICT.recovered, markAsBaseline: false, shouldAlert: true, compare };
  }
  return { verdict: VERDICT.ok, markAsBaseline: false, shouldAlert: false, compare };
};

const decideVerdict = ({ baseline, previous, currentSummary, currentCases, config, opsFailed }) => {
  const rebaselineRequested = config.rebaseline === true || config.rebaseline === 'true';
  if (!baseline || rebaselineRequested) return captureBaseline(baseline != null, opsFailed);
  return compareAgainstBaseline({ baseline, previous, currentSummary, currentCases, opsFailed });
};

const current = $('Aggregate run').first().json;
const currentSummary = current.summary;
const currentCases = current.perCase || [];
const config = $('Config').first().json;

const decision = decideVerdict({
  baseline: parseSnapshot(fetchRows('Get baseline snapshot')),
  previous: parseSnapshot(fetchRows('Get previous snapshot')),
  currentSummary,
  currentCases,
  config,
  opsFailed: detectOpsFailure(currentSummary),
});

const shouldAlert = decision.shouldAlert || config.alertMode === 'always';
const storedVerdict = decision.verdict === VERDICT.recovered ? VERDICT.ok : decision.verdict;

return [{
  json: {
    verdict: decision.verdict,
    shouldAlert,
    markAsBaseline: decision.markAsBaseline,
    compare: decision.compare,
    failing: current.failing || [],
    summary: currentSummary,
    summaryJson: JSON.stringify({ ...currentSummary, verdict: storedVerdict }),
    resultsJson: JSON.stringify(currentCases),
  },
}];

const maxFailingDetails = 5;
const maxLabelsPerSection = 10;

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const formatPercent = (rate) => (rate == null ? 'n/a' : (rate * 100).toFixed(0) + '%');

const formatSignedDelta = (value) => (value == null ? '' : (value >= 0 ? '+' : '') + value.toFixed(1));

const capLabels = (entries, limit) => {
  const labels = entries.map((entry) => escapeHtml(entry.label));
  if (labels.length <= limit) return labels;
  return labels.slice(0, limit).concat(['+' + (labels.length - limit) + ' more']);
};

const verdictLines = {
  baseline: () => '✅ BASELINE CAPTURED - future runs compare against this run.',
  rebaseline: () => '✅ NEW BASELINE SET - switch rebaseline back to false in Config.',
  regression: (comparison) => '🔴 REGRESSION vs baseline (' + escapeHtml(comparison.baselineRunAt || '') + ')',
  ops: () => '⚠️ OPS ISSUE - the eval could not run cleanly (see below).',
  recovered: () => '🟢 RECOVERED - quality is back in line with baseline.',
  ok: () => '✅ OK - no regression vs baseline.',
};

const buildVerdictLine = (verdict, comparison) => {
  const build = verdictLines[verdict] ?? verdictLines.ok;
  return build(comparison);
};

const buildHeader = (summary) =>
  '<b>Prompt regression report</b>\n' + escapeHtml(summary.runAt) + '\n'
  + summary.total + ' cases, ' + summary.evaluated + ' evaluated'
  + (summary.truncated ? ' ⚠️ at maxCases limit' : '');

const buildMetrics = (summary, comparison) => {
  const lines = [];
  lines.push('Pass rate: ' + formatPercent(summary.passRate)
    + (comparison.passRateDeltaPp != null ? ' (' + formatSignedDelta(comparison.passRateDeltaPp) + ' pp vs baseline)' : ''));
  if (summary.judgeAvgScore != null) {
    lines.push('Judge avg: ' + summary.judgeAvgScore.toFixed(2)
      + (comparison.judgeScoreDelta != null ? ' (' + formatSignedDelta(comparison.judgeScoreDelta) + ')' : ''));
  }
  for (const profile of (summary.perProfile || [])) {
    lines.push('- ' + escapeHtml(profile.profile) + ': ' + formatPercent(profile.passRate)
      + ' (' + profile.passCount + '/' + profile.evaluated + ')'
      + (profile.judgeAvgScore != null ? ', judge ' + profile.judgeAvgScore.toFixed(2) : ''));
  }
  return '<b>Metrics</b>\n' + lines.join('\n');
};

const buildFailingSection = (failing) => {
  const lines = failing.slice(0, maxFailingDetails)
    .map((entry) => escapeHtml(entry.label) + ' - ' + escapeHtml(entry.detail || ''));
  if (failing.length > maxFailingDetails) lines.push('+' + (failing.length - maxFailingDetails) + ' more');
  return '<b>Failing cases</b>\n' + lines.join('\n');
};

const buildOpsSection = (summary) =>
  '<b>Ops issues</b>\n'
  + (summary.errorCount ? summary.errorCount + ' model/judge errors\n' : '')
  + (summary.invalidCount ? summary.invalidCount + ' invalid cases' : '');

const report = $('Compare to baseline').first().json;
const summary = report.summary;
const comparison = report.compare || {};
const unconfirmed = (comparison.regressed || []).filter((entry) => !entry.confirmed);

const sections = [];
sections.push(buildHeader(summary));
sections.push(buildVerdictLine(report.verdict, comparison));
sections.push(buildMetrics(summary, comparison));

if (comparison.thresholdChanged) {
  sections.push('ℹ️ judgeScoreThreshold changed since baseline - flips are not treated as regressions this run.');
}
if ((comparison.confirmed || []).length) {
  sections.push('<b>Confirmed regressions</b>\n' + capLabels(comparison.confirmed, maxLabelsPerSection).join('\n'));
}
if (unconfirmed.length) {
  sections.push('<b>Regressions (unconfirmed, will confirm next run)</b>\n' + capLabels(unconfirmed, maxLabelsPerSection).join('\n'));
}
if ((comparison.newFailing || []).length) {
  sections.push('<b>New failures (unconfirmed, possibly flaky)</b>\n' + capLabels(comparison.newFailing, maxLabelsPerSection).join('\n'));
}
if ((report.failing || []).length) {
  sections.push(buildFailingSection(report.failing));
}
if (summary.errorCount || summary.invalidCount) {
  sections.push(buildOpsSection(summary));
}
if ((comparison.recovered || []).length) {
  sections.push('<b>Recovered</b>\n' + capLabels(comparison.recovered, maxLabelsPerSection).join('\n'));
}
if (comparison.prevRunAt) {
  sections.push('Previous run ' + escapeHtml(comparison.prevRunAt) + ': pass rate ' + formatPercent(comparison.prevPassRate));
}

const subject = 'Prompt eval: ' + String(report.verdict).toUpperCase() + ' - pass ' + formatPercent(summary.passRate);
return [{ json: { sections, subject } }];
